values
('economics:3-8-limitations-of-markets:fib:d5e8c920', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'fib', 'fib', 2, '{"question": "The ___B1___ problem means people can benefit from a good without ___B2___ for it, so firms cannot profit from supplying it.", "blankOptions": {"B1": ["right", "third", "free-rider", "private"], "B2": ["paying", "social", "price", "demand"]}}'::jsonb, '{"blanks": {"B1": "free-rider", "B2": "paying"}}'::jsonb),
('economics:3-8-limitations-of-markets:fib:85fb0685', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'fib', 'fib', 2, '{"question": "Opportunity cost is the next best ___B1___ given up when the government spends money on one policy instead of ___B2___.", "blankOptions": {"B1": ["third", "right", "alternative", "social"], "B2": ["another", "social", "right", "free-rider"]}}'::jsonb, '{"blanks": {"B1": "alternative", "B2": "another"}}'::jsonb),
('economics:3-8-limitations-of-markets:match:d78e6cb4', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Externality”?", "options": ["The benefit received directly by the producer or consumer", "A cost or benefit of an economic activity that falls on a third party", "Private benefit plus the external benefit enjoyed by third parties", "Private cost plus the external cost imposed on third parties"]}'::jsonb, '{"answer": 1, "explain": "“Externality” means: A cost or benefit of an economic activity that falls on a third party"}'::jsonb),
('economics:3-8-limitations-of-markets:match:0769117c', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Negative externality”?", "options": ["A cost or benefit of an economic activity that falls on a third party", "Money paid to a producer to lower costs and increase supply", "A cost to a third party not reflected in the market price", "A tax on a good or service that raises a firm''s costs and shifts supply left"]}'::jsonb, '{"answer": 2, "explain": "“Negative externality” means: A cost to a third party not reflected in the market price"}'::jsonb),
('economics:3-8-limitations-of-markets:match:9b2df420', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Positive externality”?", "options": ["A cost or benefit of an economic activity that falls on a third party", "A benefit to a third party not reflected in the market price", "The cost paid directly by the producer or consumer", "A cost to a third party not reflected in the market price"]}'::jsonb, '{"answer": 1, "explain": "“Positive externality” means: A benefit to a third party not reflected in the market price"}'::jsonb),
('economics:3-8-limitations-of-markets:match:13efdc52', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Private cost”?", "options": ["A cost or benefit of an economic activity that falls on a third party", "A cost to a third party not reflected in the market price", "Money paid to a producer to lower costs and increase supply", "The cost paid directly by the producer or consumer"]}'::jsonb, '{"answer": 3, "explain": "“Private cost” means: The cost paid directly by the producer or consumer"}'::jsonb),
('economics:3-8-limitations-of-markets:match:7b094fa3', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Social cost”?", "options": ["Government directly supplying a good or service, e.g. the NHS", "Private cost plus the external cost imposed on third parties", "Laws that ban or restrict a harmful activity directly", "A tax on a good or service that raises a firm''s costs and shifts supply left"]}'::jsonb, '{"answer": 1, "explain": "“Social cost” means: Private cost plus the external cost imposed on third parties"}'::jsonb),
('economics:3-8-limitations-of-markets:match:a498dae3', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Private benefit”?", "options": ["A tax on a good or service that raises a firm''s costs and shifts supply left", "Money paid to a producer to lower costs and increase supply", "The benefit received directly by the producer or consumer", "Benefiting from a good or service without paying for it"]}'::jsonb, '{"answer": 2, "explain": "“Private benefit” means: The benefit received directly by the producer or consumer"}'::jsonb),
('economics:3-8-limitations-of-markets:match:325e7caa', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Social benefit”?", "options": ["Government campaigns to encourage or discourage consumption of a good", "Benefiting from a good or service without paying for it", "Private benefit plus the external benefit enjoyed by third parties", "A cost or benefit of an economic activity that falls on a third party"]}'::jsonb, '{"answer": 2, "explain": "“Social benefit” means: Private benefit plus the external benefit enjoyed by third parties"}'::jsonb),
('economics:3-8-limitations-of-markets:match:8d75beba', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Free-rider problem”?", "options": ["Money paid to a producer to lower costs and increase supply", "A cost or benefit of an economic activity that falls on a third party", "Benefiting from a good or service without paying for it", "A cost to a third party not reflected in the market price"]}'::jsonb, '{"answer": 2, "explain": "“Free-rider problem” means: Benefiting from a good or service without paying for it"}'::jsonb),
('economics:3-8-limitations-of-markets:match:8f7a7de8', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Indirect tax”?", "options": ["Money paid to a producer to lower costs and increase supply", "A tax on a good or service that raises a firm''s costs and shifts supply left", "Laws that ban or restrict a harmful activity directly", "Government campaigns to encourage or discourage consumption of a good"]}'::jsonb, '{"answer": 1, "explain": "“Indirect tax” means: A tax on a good or service that raises a firm''s costs and shifts supply left"}'::jsonb),
('economics:3-8-limitations-of-markets:match:776d176c', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Subsidy”?", "options": ["A tax on a good or service that raises a firm''s costs and shifts supply left", "Benefiting from a good or service without paying for it", "Money paid to a producer to lower costs and increase supply", "A cost or benefit of an economic activity that falls on a third party"]}'::jsonb, '{"answer": 2, "explain": "“Subsidy” means: Money paid to a producer to lower costs and increase supply"}'::jsonb),
('economics:3-8-limitations-of-markets:match:fa3928ed', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “State provision”?", "options": ["A cost or benefit of an economic activity that falls on a third party", "Government directly supplying a good or service, e.g. the NHS", "Private cost plus the external cost imposed on third parties", "Private benefit plus the external benefit enjoyed by third parties"]}'::jsonb, '{"answer": 1, "explain": "“State provision” means: Government directly supplying a good or service, e.g. the NHS"}'::jsonb),
('economics:3-8-limitations-of-markets:match:e3240f44', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Legislation / regulation”?", "options": ["A cost to a third party not reflected in the market price", "Benefiting from a good or service without paying for it", "Government directly supplying a good or service, e.g. the NHS", "Laws that ban or restrict a harmful activity directly"]}'::jsonb, '{"answer": 3, "explain": "“Legislation / regulation” means: Laws that ban or restrict a harmful activity directly"}'::jsonb),
('economics:3-8-limitations-of-markets:match:b26fb381', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Information provision”?", "options": ["Government campaigns to encourage or discourage consumption of a good", "A benefit to a third party not reflected in the market price", "Government directly supplying a good or service, e.g. the NHS", "A cost to a third party not reflected in the market price"]}'::jsonb, '{"answer": 0, "explain": "“Information provision” means: Government campaigns to encourage or discourage consumption of a good"}'::jsonb),
('economics:4-1-importance-of-international-trade:exam:b2549b16', 'economics', 'economics:4-1-importance-of-international-trade', '4.1 Importance of International Trade', 'exam', 'mcq', 1, '{"num": "Q1", "question": "One reason why countries engage in international trade is that", "options": ["it reduces the budget deficit", "some countries are worse off as a result", "specialisation increases countries'' standards of living", "transport costs are high"], "hint": "Trade''s core justification is specialisation raising output and living standards — not the budget deficit, and it isn''t true that trade always leaves someone worse off.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: C — specialisation increases countries'' standards of living</strong></p>\n<ul>\n<li>Trade lets countries specialise in what they produce relatively most efficiently, raising total output and living standards. It does not automatically reduce a budget deficit, it is not true that some countries are always worse off, and high transport costs would discourage trade, not cause it.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:4-1-importance-of-international-trade:exam:4ebb8a3c', 'economics', 'economics:4-1-importance-of-international-trade', '4.1 Importance of International Trade', 'exam', 'mcq', 1, '{"num": "Q2", "question": "If the Chinese government introduces a tax on imported cars, this may", "options": ["decrease the price of cars in China", "decrease the production of cars in China", "increase the Chinese government''s income", "increase the quantity of car imports into China"], "hint": "A tax on imports is a tariff — tariffs raise government revenue directly. Think about what a tariff does to price and quantity of imports, not domestic production.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: C — increase the Chinese government''s income</strong></p>\n<ul>\n<li>A tariff is collected by the government on every unit imported, so it directly raises government revenue. It would tend to RAISE the price of imported cars (not decrease it) and REDUCE the quantity imported (not increase it), and it need not decrease domestic car production.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:4-1-importance-of-international-trade:exam:7d9f63c8', 'economics', 'economics:4-1-importance-of-international-trade', '4.1 Importance of International Trade', 'exam', 'mcq', 1, '{"num": "Q3", "question": "Member states of the EU agree to", "options": ["only trade with each other", "share a common income tax rate", "share a common interest rate", "trade with each other without trade barriers"], "hint": "The EU is a single market — barrier-free trade between members is the defining feature. Members do NOT share one income tax rate, and only euro-zone members share a common interest rate.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1a)</h5>\n<p><strong>Answer: D — trade with each other without trade barriers</strong></p>\n<ul>\n<li>The EU single market removes trade barriers between members. Members are free to trade with non-EU countries too, so A is wrong; income tax rates are set nationally, and only euro-using members share the same interest rate, set by the European Central Bank.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:4-1-importance-of-international-trade:exam:bd20e9b0', 'economics', 'economics:4-1-importance-of-international-trade', '4.1 Importance of International Trade', 'exam', 'mcq', 1, '{"num": "Q4", "question": "If a country has no international trade, which one of the following is always correct?", "options": ["Exports are greater than imports", "Imports are greater than exports", "The government budget is balanced", "There are no exports or imports"], "hint": "''No international trade'' means autarky — by definition there is nothing crossing the border in either direction.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1a)</h5>\n<p><strong>Answer: D — There are no exports or imports</strong></p>\n<ul>\n<li>With no international trade, both exports and imports must be zero — you cannot have one greater than the other, and the government''s budget balance is a separate, unrelated matter.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:4-1-importance-of-international-trade:exam:c21f6e17', 'economics', 'economics:4-1-importance-of-international-trade', '4.1 Importance of International Trade', 'exam', 'mcq', 1, '{"num": "Q6", "question": "The USA, Canada and Mexico have worked together to reduce import and export taxes. They have also established some common employment regulations. This is an example of a", "options": ["current account surplus", "free trade agreement", "monetary policy", "negative externality"], "hint": "Three named countries cooperating to cut import/export taxes between themselves is the textbook description of a free trade agreement (this is NAFTA).", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: B — free trade agreement</strong></p>\n<ul>\n<li>Reducing import/export taxes between named countries is exactly what a free trade agreement does. It is not a current account surplus, a form of monetary policy, or a negative externality.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>A significant proportion of candidates correctly identified the correct answer (B).</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:4-1-importance-of-international-trade:exam:6589c38a', 'economics', 'economics:4-1-importance-of-international-trade', '4.1 Importance of International Trade', 'exam', 'mcq', 1, '{"num": "Q7", "question": "An increase in a country''s level of international trade will most likely benefit producers because", "options": ["better quality finished goods will be available", "prices will be lower due to increased competition", "there will be a greater choice of goods and services", "there will be a larger market for buying inputs"], "hint": "The question asks specifically about PRODUCERS. Better quality, lower prices and greater choice are all CONSUMER benefits — the producer-side benefit is being able to buy inputs from a much bigger market.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: D — there will be a larger market for buying inputs</strong></p>\n<ul>\n<li>A larger market for buying raw materials and components is a direct PRODUCER benefit. Better quality, lower prices and greater choice are benefits that fall on CONSUMERS.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>A significant proportion of candidates correctly identified the correct answer (D).</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:4-1-importance-of-international-trade:exam:c0d865e2', 'economics', 'economics:4-1-importance-of-international-trade', '4.1 Importance of International Trade', 'exam', 'mcq', 1, '{"num": "Q8", "question": "If a country enters into a free trade agreement, it is most likely to lead to a decrease in the", "options": ["country''s economic growth", "level of imports", "standard of living in other countries", "unemployment in the country"], "hint": "FTAs expand trade and output, which tends to create jobs — think about what happens to jobs, not growth or imports, which would be expected to RISE.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: D — unemployment in the country</strong></p>\n<ul>\n<li>Expanding trade tends to raise output and create jobs, so unemployment is likely to FALL. Economic growth and imports would be expected to RISE, not fall, and the standard of living in OTHER countries is not what the question asks about.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>A significant proportion of candidates answered D correctly.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:4-1-importance-of-international-trade:exam:840d30fa', 'economics', 'economics:4-1-importance-of-international-trade', '4.1 Importance of International Trade', 'exam', 'mcq', 1, '{"num": "Q9", "question": "A benefit for UK producers of international trade is", "options": ["an improvement in the current account", "an increase in imported goods and services", "greater variety of goods for consumers", "increased economies of scale in production"], "hint": "Again, the question is about PRODUCERS specifically. Economies of scale (falling unit costs as output rises) is the clean producer-side benefit; the other three are either consumer benefits or unrelated macro outcomes.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: D — increased economies of scale in production</strong></p>\n<ul>\n<li>Selling into bigger export markets lets producers raise output and benefit from economies of scale. Greater variety is a CONSUMER benefit, more imports is not obviously a \"benefit\", and the current account is not guaranteed to improve.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>A significant proportion of candidates answered D correctly.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:4-1-importance-of-international-trade:exam:42b08475', 'economics', 'economics:4-1-importance-of-international-trade', '4.1 Importance of International Trade', 'exam', 'mcq', 1, '{"num": "Q10", "question": "What is a benefit for consumers of international trade?", "options": ["Easier to sell products abroad", "Greater choice of goods", "Less competition", "Lower costs of production"], "hint": "This time the question is about CONSUMERS. ''Easier to sell products abroad'' and ''lower costs of production'' are producer-side ideas, and trade brings MORE competition, not less.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: B — Greater choice of goods</strong></p>\n<ul>\n<li>Consumers gain from the wider range of goods and services trade makes available. Selling abroad and lower production costs are producer-side ideas, and trade INCREASES competition rather than reducing it.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>A significant proportion of candidates correctly answered B, although some confused consumers and firms (incorrectly answering A or D).</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:4-1-importance-of-international-trade:exam:67539c85', 'economics', 'economics:4-1-importance-of-international-trade', '4.1 Importance of International Trade', 'exam', 'mcq', 1, '{"num": "Q13", "question": "Penham Chemicals have decided to grow the business by taking part in international trade. The most likely benefit to them of doing this would be", "options": ["access to free trade agreements", "improved production and productivity", "larger market for buying inputs", "technological innovation"], "hint": "This mirrors the earlier ''producer benefit'' MCQs — the direct benefit of trade to a growing firm is a bigger market to buy its inputs from, not the other more indirect effects listed.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: C — larger market for buying inputs</strong></p>\n<ul>\n<li>A larger market for buying inputs is the most direct benefit trade offers a growing firm. Access to free trade agreements, improved productivity and technological innovation may follow, but they are not the immediate benefit described.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:4-1-importance-of-international-trade:exam:a8c9a675', 'economics', 'economics:4-1-importance-of-international-trade', '4.1 Importance of International Trade', 'exam', 'mcq', 1, '{"num": "Q14", "question": "The benefits of international trade are only fully achieved if there is", "options": ["a constant exchange rate", "free trade", "globalisation", "no opportunity cost"], "hint": "The theoretical gains from trade rely on countries being able to trade WITHOUT barriers — that is free trade, not a fixed exchange rate or the broader idea of globalisation.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: B — free trade</strong></p>\n<ul>\n<li>The full gains from specialisation and trade rely on trade being genuinely FREE — without tariffs, quotas or other barriers. A constant exchange rate is not required, globalisation is a broader process rather than a precondition, and opportunity cost cannot be eliminated.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:4-1-importance-of-international-trade:exam:ef0a06a1', 'economics', 'economics:4-1-importance-of-international-trade', '4.1 Importance of International Trade', 'exam', 'mcq', 1, '{"num": "Q15", "question": "A free trade agreement between two countries is where:", "options": ["goods and services move between countries without restrictions", "the benefits of imports and exports are available to all", "the costs of trade are offset by the benefits a country gains", "the movement of goods and services between countries is regulated"], "hint": "''Without restrictions'' between the agreement''s own members is the definition. The other options describe outcomes or unrelated ideas, not the definition itself — and ''regulated'' is closer to protectionism than free trade.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: A — goods and services move between countries without restrictions</strong></p>\n<ul>\n<li>This is the core definition of a free trade agreement. Options B and C describe possible OUTCOMES rather than the definition, and option D describes the opposite — regulated trade is closer to protectionism.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:4-1-importance-of-international-trade:mcq:321e9e56', 'economics', 'economics:4-1-importance-of-international-trade', '4.1 Importance of International Trade', 'mcq', 'mcq', 1, '{"question": "Which of these is an example of a VISIBLE import into the UK?", "options": ["A holiday in France bought by a UK resident (a service)", "Financial advice bought from a US bank (a service)", "A German car imported into the UK (a good)", "A music streaming subscription bought from a Swedish company (a service)"]}'::jsonb, '{"answer": 2, "explain": "Visible trade is trade in tangible GOODS — a car is something you can touch. The other three are all SERVICES, so they count as invisible trade."}'::jsonb),
('economics:4-1-importance-of-international-trade:mcq:7d0382c4', 'economics', 'economics:4-1-importance-of-international-trade', '4.1 Importance of International Trade', 'mcq', 'mcq', 1, '{"question": "A government imposes a tariff on imported steel. The most likely immediate effect is...", "options": ["The price of steel in the domestic market falls", "Total imports of steel increase", "The government''s spending automatically rises", "Imports of steel become relatively more expensive"]}'::jsonb, '{"answer": 3, "explain": "A tariff is a tax added to an imported good, so imported steel becomes dearer relative to domestic steel. Prices would not fall, imports would not rise, and government SPENDING isn''t automatically affected (though tax revenue might rise)."}'::jsonb),
('economics:4-1-importance-of-international-trade:mcq:3b889a0b', 'economics', 'economics:4-1-importance-of-international-trade', '4.1 Importance of International Trade', 'mcq', 'mcq', 1, '{"question": "Which is the best definition of a quota?", "options": ["A subsidy paid to a domestic producer", "An agreement to remove all trade barriers", "A tax added to the price of an imported good", "A limit on the quantity of a good that can be imported"]}'::jsonb, '{"answer": 3, "explain": "A quota restricts the QUANTITY of a good that can be imported. A tax on imports is a tariff — don''t mix the two up."}'::jsonb),
('economics:4-1-importance-of-international-trade:mcq:05d1dbc6', 'economics', 'economics:4-1-importance-of-international-trade', '4.1 Importance of International Trade', 'mcq', 'mcq', 1, '{"question": "Two countries specialise in what they produce most efficiently and then trade. Compared with each country trying to produce everything itself, total world output...", "options": ["Rises, because resources are used where they are relatively most productive", "Is unaffected, because output depends only on population size", "Falls, because trade always creates a loser", "Falls, because specialisation reduces variety"]}'::jsonb, '{"answer": 0, "explain": "Specialisation lets each country''s resources go towards what they are relatively best at producing, raising total combined output compared with every country trying to produce everything itself."}'::jsonb),
('economics:4-1-importance-of-international-trade:mcq:f3697772', 'economics', 'economics:4-1-importance-of-international-trade', '4.1 Importance of International Trade', 'mcq', 'mcq', 1, '{"question": "Which of the following is a benefit of trade specifically for a UK PRODUCER, rather than for a UK consumer?", "options": ["Access to a market far larger than the domestic economy alone", "Wider choice of goods to buy", "Access to goods that cannot be made domestically", "Lower prices from foreign competition"]}'::jsonb, '{"answer": 0, "explain": "A bigger market to sell into is a direct benefit to a PRODUCER. Choice, lower prices from competition, and access to otherwise-unavailable goods are all CONSUMER benefits."}'::jsonb),
('economics:4-1-importance-of-international-trade:mcq:69150057', 'economics', 'economics:4-1-importance-of-international-trade', '4.1 Importance of International Trade', 'mcq', 'mcq', 1, '{"question": "As a firm''s output rises due to selling into export markets, its average cost per unit typically...", "options": ["Becomes impossible to measure", "Falls, due to economies of scale", "Rises, due to diminishing returns", "Stays the same, because costs are fixed"]}'::jsonb, '{"answer": 1, "explain": "Selling into bigger markets lets a firm raise output and spread its costs over more units — economies of scale, which LOWER the average cost per unit."}'::jsonb),
('economics:4-1-importance-of-international-trade:mcq:f6e0ad77', 'economics', 'economics:4-1-importance-of-international-trade', '4.1 Importance of International Trade', 'mcq', 'mcq', 1, '{"question": "Which of these is the best example of structural unemployment caused by trade?", "options": ["A worker temporarily laid off during a national holiday", "A worker made redundant after their factory closes because it cannot compete with cheaper imports, and lacks the skills for new local industries", "A worker who resigns to travel for six months", "A worker who retires at the normal retirement age"]}'::jsonb, '{"answer": 1, "explain": "Structural unemployment happens when a whole industry declines — often because it can''t compete with imports — and its workers'' skills no longer match the jobs that are available."}'::jsonb),
('economics:4-1-importance-of-international-trade:mcq:83a6b464', 'economics', 'economics:4-1-importance-of-international-trade', '4.1 Importance of International Trade', 'mcq', 'mcq', 1, '{"question": "''Dumping'' in international trade describes...", "options": ["A tariff being removed between two trading partners", "Two countries merging their currencies", "A country selling a surplus of a good abroad at a very low price, undercutting local producers", "A country banning all imports of a good"]}'::jsonb, '{"answer": 2, "explain": "Dumping is when a country with a big cost advantage in a good (often agricultural) sells its surplus abroad very cheaply, driving local producers out of that market."}'::jsonb),
('economics:4-1-importance-of-international-trade:mcq:ac316cdd', 'economics', 'economics:4-1-importance-of-international-trade', '4.1 Importance of International Trade', 'mcq', 'mcq', 1, '{"question": "Within a free trade agreement, which is true?", "options": ["Members must share a single currency", "Members can still set their own trade rules with countries outside the agreement", "No trade occurs between members at all", "Members must share the same interest rate"]}'::jsonb, '{"answer": 1, "explain": "An FTA removes barriers BETWEEN its own members, but each member remains free to make its own separate trade arrangements with countries outside the group."}'::jsonb),
('economics:4-1-importance-of-international-trade:mcq:6937ecde', 'economics', 'economics:4-1-importance-of-international-trade', '4.1 Importance of International Trade', 'mcq', 'mcq', 1, '{"question": "The UK–EU Trade and Cooperation Agreement (after Brexit) guarantees zero tariffs and zero quotas on trade in...", "options": ["Neither goods nor services", "Services only, not goods", "Goods only, not services", "All goods and all services"]}'::jsonb, '{"answer": 2, "explain": "The deal guarantees zero tariffs and zero quotas on GOODS, but this does not extend to services — a gap that matters for the UK''s large financial services sector."}'::jsonb),
('economics:4-1-importance-of-international-trade:tf:468f996e', 'economics', 'economics:4-1-importance-of-international-trade', '4.1 Importance of International Trade', 'tf', 'tf', 1, '{"question": "A free trade agreement means member countries no longer have any trade barriers with countries outside the agreement."}'::jsonb, '{"answer": false, "explain": "An FTA removes barriers only BETWEEN its own members. Each member is still free to set its own separate trade arrangements — including barriers — with countries outside the group."}'::jsonb),
('economics:4-1-importance-of-international-trade:tf:aacf3c43', 'economics', 'economics:4-1-importance-of-international-trade', '4.1 Importance of International Trade', 'tf', 'tf', 1, '{"question": "Specialisation and trade can increase total output compared with every country trying to produce everything itself."}'::jsonb, '{"answer": true, "explain": "When each country focuses its resources on what it produces relatively most efficiently and then trades, combined output rises above what both could produce by splitting resources evenly between goods."}'::jsonb),
('economics:4-1-importance-of-international-trade:tf:6d91ec89', 'economics', 'economics:4-1-importance-of-international-trade', '4.1 Importance of International Trade', 'tf', 'tf', 1, '{"question": "Cheaper imported inputs are a benefit of trade only for consumers, not producers."}'::jsonb, '{"answer": false, "explain": "Cheaper inputs (raw materials, components) are a direct PRODUCER benefit — it lowers their costs of production. Consumers benefit separately from cheaper finished goods."}'::jsonb),
('economics:4-1-importance-of-international-trade:tf:e2319576', 'economics', 'economics:4-1-importance-of-international-trade', '4.1 Importance of International Trade', 'tf', 'tf', 1, '{"question": "A tariff is a limit on the quantity of a good that can be imported."}'::jsonb, '{"answer": false, "explain": "That describes a QUOTA. A tariff is a TAX added to the price of an imported good — the two tools work differently (price vs quantity)."}'::jsonb),
('economics:4-1-importance-of-international-trade:tf:1b9b8c8a', 'economics', 'economics:4-1-importance-of-international-trade', '4.1 Importance of International Trade', 'tf', 'tf', 1, '{"question": "Structural unemployment can occur when a country''s industries decline because they cannot compete with cheaper imports."}'::jsonb, '{"answer": true, "explain": "If workers'' skills no longer match the jobs available after their industry shrinks — as with UK mining and textiles — this is structural unemployment."}'::jsonb),
('economics:4-1-importance-of-international-trade:tf:3553340e', 'economics', 'economics:4-1-importance-of-international-trade', '4.1 Importance of International Trade', 'tf', 'tf', 1, '{"question": "Trade can only ever benefit both trading countries equally — there are no losers."}'::jsonb, '{"answer": false, "explain": "Even if a country gains overall, there are winners (export-competitive industries) and losers (import-competing industries) WITHIN it, and gains between two trading countries are rarely equal."}'::jsonb),
('economics:4-1-importance-of-international-trade:tf:c749e7a9', 'economics', 'economics:4-1-importance-of-international-trade', '4.1 Importance of International Trade', 'tf', 'tf', 1, '{"question": "The EU single market guarantees free movement of goods, services, capital AND people between member states."}'::jsonb, '{"answer": true, "explain": "All four freedoms — goods, services, capital and people — are guaranteed within the EU single market, which is more than a typical free trade agreement offers."}'::jsonb),
('economics:4-1-importance-of-international-trade:tf:02622131', 'economics', 'economics:4-1-importance-of-international-trade', '4.1 Importance of International Trade', 'tf', 'tf', 1, '{"question": "Dumping means a country bans all imports of a particular good."}'::jsonb, '{"answer": false, "explain": "Dumping means selling a SURPLUS of a good abroad at a very low price, undercutting and driving out local producers — the opposite of banning imports."}'::jsonb),
('economics:4-1-importance-of-international-trade:learn:883ba198', 'economics', 'economics:4-1-importance-of-international-trade', '4.1 Importance of International Trade', 'learn', 'mcq', 1, '{"readingTitle": "Why countries trade — specialisation and comparative advantage", "reading": "<p><strong>International trade is the exchange of goods and services across national borders.</strong> A country''s <strong>exports</strong> are the goods and services it sells to other countries; its <strong>imports</strong> are the goods and services it buys from other countries.</p>\n<h4>Visible and invisible trade</h4>\n<ul>\n<li><strong>Goods are tangible</strong> — you can touch them, e.g. a car. A <strong>visible import</strong> is a tangible product, such as a Fiat car bought from an Italian producer.</li>\n<li><strong>Services are intangible</strong> — you cannot touch them, e.g. finance. An <strong>invisible import</strong> is an intangible product, such as a UK resident''s holiday in France.</li>\n<li>Every country takes part in international trade to some extent. Some, such as the UK, have extensive trade; others, such as North Korea, have very little.</li>\n</ul>\n<h4>Why countries specialise and trade</h4>\n<ul>\n<li>Countries differ in their resources — climate, natural resources, skills, technology and labour costs — so each can produce certain goods or services relatively more efficiently than others.</li>\n<li>By specialising in what they do best and trading for the rest, total global output and consumer choice both increase, compared with every country trying to produce everything itself.</li>\n<li><strong>Worked example:</strong> Country A has high rainfall (good for milk); Country B has lots of sunshine (good for bananas). Splitting resources 50/50 between the two goods, together they produce 8,000 litres of milk and 10 tonnes of bananas. If each specialises fully instead, Country A can produce 12,000 litres of milk and Country B 16 tonnes of bananas — 4,000 more litres and 6 more tonnes than before, from the SAME total resources.</li>\n<li>The UK''s own specialism is <strong>services</strong> — it imports many agricultural and manufactured products, while exporting finance, education and other highly differentiated services.</li>\n</ul>", "question": "Two countries split their resources evenly between two goods and produce a combined 8,000 litres of milk and 10 tonnes of bananas. If each specialises fully in the good it is better suited to, what happens to combined output?", "options": ["It stays the same, only which country makes what changes", "It falls, because specialising removes choice", "It rises, because each country produces more of what it is relatively better at", "It becomes impossible to compare"]}'::jsonb, '{"answer": 2, "explain": "Specialisation lets each country focus its resources on its strongest good, raising total output above what both could produce by splitting resources evenly — the basic case for trade."}'::jsonb),
('economics:4-1-importance-of-international-trade:learn:1db3f5f4', 'economics', 'economics:4-1-importance-of-international-trade', '4.1 Importance of International Trade', 'learn', 'mcq', 1, '{"readingTitle": "The benefits of trade — for consumers, producers and the economy", "reading": "<p>The spec asks you to explain the benefits of trade separately for <strong>consumers</strong> and <strong>producers</strong> — exam questions often name one, so keep them apart.</p>\n<h4>Benefits for consumers</h4>\n<ul>\n<li><strong>Greater choice</strong> of goods and services, including products that could not be produced domestically at all, e.g. tropical fruit in the UK.</li>\n<li><strong>Lower prices</strong> — more global competition forces firms to be efficient and price-competitive.</li>\n<li><strong>Higher quality and more innovation</strong> — specialist producers competing internationally are pushed to improve their products.</li>\n<li>Trade can also contribute to <strong>price stability</strong>, since import prices can be a lot cheaper than domestically produced equivalents.</li>\n</ul>\n<h4>Benefits for producers</h4>\n<ul>\n<li><strong>A bigger market</strong> to sell into, far beyond the domestic economy.</li>\n<li><strong>Economies of scale</strong> from higher output, which lowers average (unit) costs.</li>\n<li><strong>Cheaper and more varied inputs</strong> — a larger market for buying raw materials and components.</li>\n<li><strong>Spreading risk</strong> — operating in several geographical markets reduces the impact of a downturn in any one of them, particularly the domestic market.</li>\n<li><strong>Spread of technical knowledge</strong> — trading with foreign businesses can bring new technology, skills and ideas into a firm''s own operations.</li>\n</ul>\n<h4>Benefits for the wider economy</h4>\n<ul>\n<li>Export revenue supports <strong>economic growth</strong> and <strong>employment</strong>.</li>\n<li>Access to imported raw materials and components supports domestic production that could not otherwise happen.</li>\n<li>As other countries'' incomes rise from selling their own exports, they buy more imports too — trade can raise growth on a <strong>global</strong> scale, not just domestically.</li>\n<li>More trade and higher incomes generate more <strong>tax revenue</strong> (income tax, VAT, corporation tax), which can fund public services such as health and education.</li>\n</ul>", "question": "A UK exporter can now buy cheaper components from overseas suppliers as trade increases. This is best described as a benefit of trade for...", "options": ["Consumers, through lower prices", "Producers, through cheaper inputs", "The government, through higher tax revenue", "Consumers, through greater choice"]}'::jsonb, '{"answer": 1, "explain": "Cheaper inputs for a FIRM''S OWN production is a producer benefit — a bigger, more competitive market for buying supplies. Cheaper prices for shoppers would be the consumer version."}'::jsonb),
('economics:4-1-importance-of-international-trade:learn:16dea5aa', 'economics', 'economics:4-1-importance-of-international-trade', '4.1 Importance of International Trade', 'learn', 'mcq', 1, '{"readingTitle": "The risks and costs of international trade", "reading": "<p>Trade is not free of costs — the spec expects you to weigh benefits against risks, for both a country and its firms.</p>\n<h4>Structural unemployment</h4>\n<ul>\n<li>Domestic industries that cannot compete with cheaper imports may decline, and their workers may lack the skills needed by growing industries — causing <strong>structural unemployment</strong>.</li>\n<li>Real examples: the decline of <strong>mining in the north of England</strong> left many workers without transferable skills, and structural unemployment persists there today. <strong>Textiles in Yorkshire</strong> is a similar case.</li>\n<li><strong>Infant industries</strong> — new, developing firms — can struggle to compete with established multinationals, limiting local employment opportunities.</li>\n</ul>\n<h4>Over-dependence and vulnerability</h4>\n<ul>\n<li><strong>Over-reliance on imports</strong> for essential goods (food, energy, medicine) creates vulnerability to global supply shocks.</li>\n<li><strong>Over-reliance on a narrow range of exports</strong> is risky if world demand for them changes: around <strong>40% of Ivory Coast''s exports are cocoa products</strong> — a shift in chocolate demand, a drought, or new competitors could seriously damage its economy.</li>\n</ul>\n<h4>Inequality and other costs</h4>\n<ul>\n<li>Trade can widen inequality WITHIN a country, between winners (export-competitive industries) and losers (import-competing industries).</li>\n<li><strong>Dumping</strong>: countries with a big cost advantage in a good (often agricultural) sell their surplus abroad at very low prices, driving local producers out of the market.</li>\n<li><strong>Environmental costs</strong>: transporting large quantities of goods around the world uses significant scarce resources and is a growing environmental concern; over-exploitation of natural resources (mining, forestry, fishing) can also leave nothing for future generations.</li>\n</ul>", "question": "Around 40% of Ivory Coast''s export revenue comes from cocoa products. This narrow specialisation is risky mainly because...", "options": ["Cocoa cannot be traded internationally", "It guarantees structural unemployment", "It means the country cannot import anything else", "A fall in world cocoa demand or prices would seriously damage the whole economy"]}'::jsonb, '{"answer": 3, "explain": "Being heavily dependent on one export makes an economy vulnerable — if demand, prices or supply conditions for that one good change, there is no other major export to fall back on."}'::jsonb),
('economics:4-1-importance-of-international-trade:learn:8773e022', 'economics', 'economics:4-1-importance-of-international-trade', '4.1 Importance of International Trade', 'learn', 'mcq', 1, '{"readingTitle": "Free trade agreements and trade blocs", "reading": "<p>Governments can choose to remove trade barriers between themselves and named partner countries — the opposite of protectionism.</p>\n<h4>Key definitions</h4>\n<ul>\n<li>A <strong>tariff</strong> is a tax a government charges on imports, raising their price to discourage purchase.</li>\n<li>A <strong>quota</strong> is a limit on the quantity of a good that can be imported in a given period.</li>\n<li>A <strong>free trade agreement (FTA)</strong> is where two or more countries agree to remove tariffs and quotas on trade between themselves — but each country can still make its OWN separate trade deals with countries outside the agreement. Examples include NAFTA (USA, Canada, Mexico) and EFTA.</li>\n<li>A <strong>trade bloc</strong> is a group of countries that join together to reduce barriers to trade between members. Trade between them becomes easier and cheaper, but countries OUTSIDE the bloc still face barriers.</li>\n</ul>\n<h4>The EU / European single market</h4>\n<ul>\n<li>The EU is an economic and political union operating as a <strong>single market</strong>, guaranteeing free movement of goods, services, capital AND people between member states — not just goods.</li>\n<li>All members must follow common standards and laws (e.g. product safety) to allow that free movement, and the EU negotiates trade deals with non-EU countries on behalf of all its members.</li>\n<li>Evidence suggests single-market GDP for EU countries was around <strong>9% higher</strong> than it would have been with tariff/non-tariff barriers in place.</li>\n</ul>\n<h4>Advantages and disadvantages of FTAs</h4>\n<ul>\n<li><strong>Trade creation</strong> (more trade within the bloc, since barriers are gone) vs <strong>trade diversion</strong> (a common external tariff can divert trade away, making some goods more expensive).</li>\n<li><strong>Stronger competition</strong> drives efficiency vs the risk of <strong>monopolies</strong> forming as firms merge to exploit economies of scale.</li>\n<li><strong>Access to a much larger market</strong> vs the risk that <strong>jobs move</strong> to member states with lower labour costs.</li>\n<li><strong>Freedom of movement</strong> for workers vs the ongoing <strong>cost of membership</strong> — EU membership cost the UK around £15bn a year.</li>\n</ul>\n<h4>Brexit — a real example</h4>\n<ul>\n<li>The UK–EU Trade and Cooperation Agreement guarantees <strong>zero tariffs and zero quotas</strong> on trade in GOODS — but this does NOT extend to services, a risk for the UK''s large financial services sector.</li>\n<li>Even with zero tariffs on goods, there are extra costs from <strong>border checks</strong>, since the UK and EU no longer share identical rules — especially costly for exporters of short-shelf-life goods such as UK seafood.</li>\n</ul>", "question": "Which best describes the difference between a free trade agreement and full membership of the EU single market?", "options": ["An FTA always includes free movement of people", "There is no difference, they mean the same thing", "The EU single market only covers goods, not services", "An FTA usually removes tariffs on goods, but members can still set their own deals with others and needn''t share free movement of people"]}'::jsonb, '{"answer": 3, "explain": "An FTA typically removes tariffs/quotas between its members but leaves each country free to make its own arrangements elsewhere. Full single-market membership goes further, requiring free movement of goods, services, capital AND people, plus shared rules."}'::jsonb),
('economics:4-1-importance-of-international-trade:misc:c6bd462e', 'economics', 'economics:4-1-importance-of-international-trade', '4.1 Importance of International Trade', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"Investment from overseas comes into the UK because of high exchange rates.\"</p><p><strong>✅ The correct idea:</strong> The examiners specifically flagged this on Q5(ii) (''Explain one reason why there is significant investment from overseas into the UK''): ''a further common error/misconception was between exchange rates and interest rates''. The mark scheme''s real reasons are: financing the UK''s current account deficit, an educated workforce, English as an international language, lower corporation/business tax, belief the economy will grow, a relatively stable/developed economy, and — the one most often confused — HIGHER INTEREST RATES/returns. The exchange rate is a different concept entirely (the price of a currency in terms of another), and mixing it up with the interest rate costs marks.</p>", "question": "Which of these is a genuine reason overseas investors might invest in the UK, according to the mark scheme?", "options": ["A fixed exchange rate policy", "Falling UK GDP growth", "Higher interest rates/returns available in the UK", "A weak exchange rate against the dollar"]}'::jsonb, '{"answer": 2, "explain": "The mark scheme credits higher interest rates/returns, an educated workforce, English as an international language, and financing the deficit. Examiners specifically flagged confusing EXCHANGE rates with INTEREST rates as a common error."}'::jsonb),
('economics:4-1-importance-of-international-trade:misc:a9bdf0a6', 'economics', 'economics:4-1-importance-of-international-trade', '4.1 Importance of International Trade', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"I''ll just describe what the extract''s table shows and that counts as analysis.\"</p><p><strong>✅ The correct idea:</strong> The examiners were blunt about this on Q11(b): ''There was a tendency for some candidates to re-write the information in Extract 3 without any analysis. For example, writing \"the economy becomes less based on domestic manufacturing…\" or to describe or quote the data in the table.'' Real analysis needs the data turned into an EXPLAINED chain: the goods deficit widening from $549,253m to $924,284m while the services surplus grew from $125,839m to $286,723m SHOWS the US economy shifting from manufacturing (secondary sector) to services (tertiary sector) — and this happened BECAUSE the US has lower costs/higher productivity in services than in manufacturing. Quoting the numbers alone, without that explanation, scores poorly.</p>", "question": "For ''analyse how the data reflects changes in economic structure'', which response scores well?", "options": ["Listing every number in the table in order", "Quoting the export and import figures from the table without further comment", "Explaining that a growing goods deficit and services surplus show the economy shifting toward services, and why that is happening", "Restating the extract''s own sentence about domestic manufacturing"]}'::jsonb, '{"answer": 2, "explain": "Examiners explicitly penalised candidates who re-wrote or quoted the table without analysis. Marks need the DATA turned into an explained chain of reasoning about WHY the structure is changing."}'::jsonb),
('economics:4-1-importance-of-international-trade:misc:5600460a', 'economics', 'economics:4-1-importance-of-international-trade', '4.1 Importance of International Trade', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"Stating a cost or a reason is enough to get full marks on a 2-mark ''explain'' question.\"</p><p><strong>✅ The correct idea:</strong> Both Q5(ii) and Q12(ii) use the identical mark scheme structure: ''Award 1 mark for a statement that is not explained. Award 1 more mark for the explanation.'' The examiners repeated the same warning on Q12(ii): ''this question was generally answered well, although some candidates stated a cost, rather than explaining it.'' A named point earns only HALF the marks — the second mark needs the reasoning developed, e.g. not just ''competition from imports'' but WHY that competition harms a producer whose own productivity is lower.</p>", "question": "''Explain one cost to producers of globalisation'' is worth 2 marks. Which answer earns both marks?", "options": ["''Globalisation is bad for producers''", "''Competition from imports'' (a cost stated but not explained)", "Simply naming globalisation as a cost", "''Competition from lower-cost overseas producers can harm domestic producers whose own productivity is lower, forcing some out of business'' (stated and explained)"]}'::jsonb, '{"answer": 3, "explain": "The mark scheme awards 1 mark for stating a cost, then a 2nd mark ONLY if it is explained — i.e. the chain of reasoning for WHY it is a cost is spelled out."}'::jsonb),
('economics:4-1-importance-of-international-trade:misc:ba8fbf38', 'economics', 'economics:4-1-importance-of-international-trade', '4.1 Importance of International Trade', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"A free trade agreement means a country can no longer trade freely with anyone outside it.\"</p><p><strong>✅ The correct idea:</strong> The examiners'' comment on Q12(i) was precise: ''Most candidates identified the link between Free Trade Areas and tariffs, but few either quoted the textbook definition or identified the fact that signatories can have differing arrangements with other countries.'' A full 2-mark definition needs BOTH elements: (1) no tariffs/quotas WITHIN the group, AND (2) that members can still make their OWN separate trade deals with countries OUTSIDE the group (or a correct example, e.g. NAFTA/EFTA). Most students only ever wrote the first half.</p>", "question": "For ''explain what is meant by a free trade agreement'' (2 marks), what did examiners say most candidates missed?", "options": ["That members can also make their own separate trade deals with countries outside the group", "That there are no tariffs within the group at all", "That NAFTA is an example of an FTA", "That trade barriers exist"]}'::jsonb, '{"answer": 0, "explain": "Examiners noted most candidates got the ''no tariffs/quotas'' half but rarely mentioned that FTA members remain free to strike their OWN deals with non-members — the second mark-earning element."}'::jsonb),
('economics:4-1-importance-of-international-trade:misc:c2b22b7b', 'economics', 'economics:4-1-importance-of-international-trade', '4.1 Importance of International Trade', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"A rising current account deficit is always straightforwardly bad news, with no offsetting factors.\"</p><p><strong>✅ The correct idea:</strong> Q5(iii)''s mark scheme is built entirely from paired points: every piece of analysis is followed by its own ''However:'' counterpoint. For example: the deficit is matched by a financial-account surplus showing inward investment that brings new technology — HOWEVER that same investment means the UK''s income account tends to run a deficit too, because foreign owners'' profits flow back out. Or: the deficit puts downward pressure on the exchange rate, raising import prices — HOWEVER a weaker pound should make UK exports MORE competitive. Good evaluation always matches a point with its own genuine counter, not a one-sided list.</p>", "question": "Evaluating a current account deficit, which pairing shows the kind of BALANCED point examiners reward?", "options": ["Deficits and surpluses have identical effects", "The deficit reflects inward investment bringing new technology — however this investment also means the income account tends to run in deficit as profits flow back overseas", "The deficit is bad, full stop", "The deficit only affects the government, nobody else"]}'::jsonb, '{"answer": 1, "explain": "Good evaluation MATCHES each analytical point with its own counter — e.g. inward investment is a genuine benefit, but it also explains why the income account is often in deficit. One-sided lists don''t earn the evaluation marks."}'::jsonb),
('economics:4-1-importance-of-international-trade:tips:fb683a28', 'economics', 'economics:4-1-importance-of-international-trade', '4.1 Importance of International Trade', 'tips', 'mcq', 1, '{"readingTitle": "definition — Definitions: state BOTH required elements", "reading": "<p>The examiners were explicit on Q12(i): most candidates linked free trade agreements to tariffs, but few gave the FULL definition. Two-element definitions need BOTH parts, every time:</p>\n<ul>\n<li><strong>Free trade agreement</strong> = no import tariffs or quotas between members (1) + members can still make their OWN trade deals with countries outside the group, or a correct example such as NAFTA/EFTA (1).</li>\n<li><strong>Tariff</strong> = a tax charged on an imported good. <strong>Quota</strong> = a LIMIT on the quantity of a good that can be imported. Don''t mix them up — they are opposite tools (tax vs quantity limit).</li>\n<li><strong>Trade bloc</strong> = a group of countries that reduce trade barriers BETWEEN THEMSELVES — outsiders still face barriers.</li>\n</ul>", "question": "For ''explain what is meant by a free trade agreement'', which single addition would most likely earn the second mark?", "options": ["Repeating that tariffs are removed", "Stating that members can still make their own trade deals with non-members, or giving a correct example", "Describing a quota instead", "Saying trade always benefits both sides"]}'::jsonb, '{"answer": 1, "explain": "The mark scheme''s second mark is for the fact that FTA members remain free to strike separate deals with outsiders, OR a correct example (NAFTA/EFTA) — the element examiners said most candidates missed."}'::jsonb),
('economics:4-1-importance-of-international-trade:tips:e6aef481', 'economics', 'economics:4-1-importance-of-international-trade', '4.1 Importance of International Trade', 'tips', 'mcq', 1, '{"readingTitle": "explain — Explain questions: STATE it, then EXPLAIN it", "reading": "<p>Both Q5(ii) and Q12(ii) use the identical mark scheme structure — learn it once, apply it everywhere:</p>\n<ul>\n<li><strong>1st mark:</strong> a correct statement/reason/cost, even unexplained.</li>\n<li><strong>2nd mark:</strong> ONLY awarded if that statement is then EXPLAINED — the chain of WHY it happens.</li>\n<li>Examiners'' own words: \"some candidates stated a cost, rather than explaining it\" (Q12ii) and \"many candidates identified a reasonable reason but did not explain it\" (Q5ii).</li>\n<li>Fix: after your first sentence, always add a second sentence starting \"This means...\", \"As a result...\", or \"Because...\".</li>\n</ul>", "question": "''Explain one reason why there is significant investment from overseas into the UK'' is worth 2 marks. Writing only ''Because of the UK''s educated workforce'' scores...", "options": ["0 marks — it''s irrelevant", "It cannot be marked without a calculation", "2 marks — it''s a full answer", "1 mark — a correct but unexplained statement"]}'::jsonb, '{"answer": 3, "explain": "A correct reason with no explanation of WHY it attracts investment earns only the 1st mark. The 2nd mark needs the reasoning developed — e.g. that a skilled workforce raises productivity, making UK investment more profitable."}'::jsonb),
('economics:4-1-importance-of-international-trade:tips:2f52d931', 'economics', 'economics:4-1-importance-of-international-trade', '4.1 Importance of International Trade', 'tips', 'mcq', 1, '{"readingTitle": "data — Data questions: use the numbers, don''t just repeat them", "reading": "<p>Examiners on Q11(b) were blunt: <strong>\"There was a tendency for some candidates to re-write the information in Extract 3 without any analysis.\"</strong> Simply quoting or describing the table earns little.</p>\n<ul>\n<li><strong>Quote the actual figures</strong> as evidence (e.g. the US services surplus grew from $125,839m to $286,723m) — this shows you have used the extract, not just glanced at it.</li>\n<li><strong>Then explain what the trend MEANS</strong> — e.g. a growing services surplus alongside a widening goods deficit shows the economy shifting from manufacturing (secondary) to services (tertiary).</li>\n<li><strong>Then explain WHY</strong> it is happening — e.g. because the US has a comparative advantage/lower costs in services than in manufacturing.</li>\n<li>The best-scoring exemplar on this paper used the data \"skilfully\" with \"no suggestion of simply rewriting it\" — that phrase is the examiners'' own benchmark for a Level 3 response.</li>\n</ul>", "question": "Which response to a ''using the data, analyse...'' question scores best?", "options": ["Quoting every figure from the table in order", "Writing out the extract''s own sentences again", "Quoting a key figure, then explaining what it shows and why it is happening", "Ignoring the data and writing from memory only"]}'::jsonb, '{"answer": 2, "explain": "Examiners explicitly penalised re-writing or quoting data without analysis. The winning structure is: cite the figure, say what it shows, then explain the cause."}'::jsonb),
('economics:4-1-importance-of-international-trade:tips:46baf5bc', 'economics', 'economics:4-1-importance-of-international-trade', '4.1 Importance of International Trade', 'tips', 'mcq', 1, '{"readingTitle": "evaluate — Evaluate & Analyse: match every point with its own counter", "reading": "<p>Every 6-mark question on this paper follows the same AO2:1 / AO3a:2 / AO3b:3 split, and both evaluate questions reward a specific structure.</p>\n<ul>\n<li><strong>Q5(iii)''s mark scheme pairs every single analysis point with its own \"However:\"</strong> — e.g. inward investment brings new technology, HOWEVER it also means the income account runs a deficit as profits flow back out. Copy this pattern exactly: point, then its OWN matching counterpoint.</li>\n<li><strong>Q12(iii) instead lists Benefits, then a separate \"Evaluation may include\" section</strong> — either structure is valid, but both need a genuinely two-sided argument, not a one-sided list.</li>\n<li><strong>Name the group.</strong> Q12(iii) asks about UK PRODUCERS specifically — examiners noted candidates who strayed onto consumers or the government only \"rarely\" did so, and it cost them marks.</li>\n<li><strong>End with a clear, supported judgement</strong> — the mark scheme explicitly credits a \"final judgement (expressed clearly)\" as one of its own bullet points.</li>\n</ul>", "question": "On Q5(iii)''s mark scheme, what follows almost every analysis point?", "options": ["A new, unrelated point", "Its own matching ''However:'' counterpoint", "A repeat of the same point", "Nothing — points stand alone"]}'::jsonb, '{"answer": 1, "explain": "The mark scheme is built as point/however pairs throughout — each piece of analysis (AO3a) is matched with its own evaluation counterpoint (AO3b), which is exactly the structure a strong answer should copy."}'::jsonb),
('economics:4-1-importance-of-international-trade:fib:2d3f363b', 'economics', 'economics:4-1-importance-of-international-trade', '4.1 Importance of International Trade', 'fib', 'fib', 2, '{"question": "International trade is the exchange of goods and ___B1___ across national ___B2___.", "blankOptions": {"B1": ["20", "services", "40", "raises"], "B2": ["20", "quota", "outside", "borders"]}}'::jsonb, '{"blanks": {"B1": "services", "B2": "borders"}}'::jsonb),
