('economics:4-1-importance-of-international-trade:match:e6f5b17f', 'economics', 'economics:4-1-importance-of-international-trade', '4.1 Importance of International Trade', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “International trade”?", "options": ["Goods and services bought from other countries", "The exchange of goods and services across national borders", "A tax charged on an imported good", "Average costs falling as a firm''s output increases"]}'::jsonb, '{"answer": 1, "explain": "“International trade” means: The exchange of goods and services across national borders"}'::jsonb),
('economics:4-1-importance-of-international-trade:match:fc8415f4', 'economics', 'economics:4-1-importance-of-international-trade', '4.1 Importance of International Trade', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Exports”?", "options": ["Goods and services sold to other countries", "A limit on the quantity of a good that can be imported", "Selling a surplus of a good abroad at a very low price to undercut local producers", "The exchange of goods and services across national borders"]}'::jsonb, '{"answer": 0, "explain": "“Exports” means: Goods and services sold to other countries"}'::jsonb),
('economics:4-1-importance-of-international-trade:match:25ef6235', 'economics', 'economics:4-1-importance-of-international-trade', '4.1 Importance of International Trade', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Imports”?", "options": ["Trade in tangible goods, e.g. cars", "Goods and services sold to other countries", "A group of countries that reduce trade barriers between members", "Goods and services bought from other countries"]}'::jsonb, '{"answer": 3, "explain": "“Imports” means: Goods and services bought from other countries"}'::jsonb),
('economics:4-1-importance-of-international-trade:match:5edf42dd', 'economics', 'economics:4-1-importance-of-international-trade', '4.1 Importance of International Trade', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Visible trade”?", "options": ["Trade in tangible goods, e.g. cars", "Goods and services sold to other countries", "A tax charged on an imported good", "Members remove tariffs/quotas between themselves but keep their own deals with outsiders"]}'::jsonb, '{"answer": 0, "explain": "“Visible trade” means: Trade in tangible goods, e.g. cars"}'::jsonb),
('economics:4-1-importance-of-international-trade:match:09a3b452', 'economics', 'economics:4-1-importance-of-international-trade', '4.1 Importance of International Trade', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Invisible trade”?", "options": ["Members remove tariffs/quotas between themselves but keep their own deals with outsiders", "A tax charged on an imported good", "Goods and services sold to other countries", "Trade in intangible services, e.g. finance or tourism"]}'::jsonb, '{"answer": 3, "explain": "“Invisible trade” means: Trade in intangible services, e.g. finance or tourism"}'::jsonb),
('economics:4-1-importance-of-international-trade:match:7502891f', 'economics', 'economics:4-1-importance-of-international-trade', '4.1 Importance of International Trade', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “National specialisation”?", "options": ["Goods and services bought from other countries", "A country focusing its resources on producing what it does relatively most efficiently", "A limit on the quantity of a good that can be imported", "Members remove tariffs/quotas between themselves but keep their own deals with outsiders"]}'::jsonb, '{"answer": 1, "explain": "“National specialisation” means: A country focusing its resources on producing what it does relatively most efficiently"}'::jsonb),
('economics:4-1-importance-of-international-trade:match:bd6a6e87', 'economics', 'economics:4-1-importance-of-international-trade', '4.1 Importance of International Trade', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Economies of scale”?", "options": ["The exchange of goods and services across national borders", "Trade in intangible services, e.g. finance or tourism", "Average costs falling as a firm''s output increases", "A country focusing its resources on producing what it does relatively most efficiently"]}'::jsonb, '{"answer": 2, "explain": "“Economies of scale” means: Average costs falling as a firm''s output increases"}'::jsonb),
('economics:4-1-importance-of-international-trade:match:58313aea', 'economics', 'economics:4-1-importance-of-international-trade', '4.1 Importance of International Trade', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Tariff”?", "options": ["Members remove tariffs/quotas between themselves but keep their own deals with outsiders", "A country focusing its resources on producing what it does relatively most efficiently", "A tax charged on an imported good", "A group of countries that reduce trade barriers between members"]}'::jsonb, '{"answer": 2, "explain": "“Tariff” means: A tax charged on an imported good"}'::jsonb),
('economics:4-1-importance-of-international-trade:match:db2e72ed', 'economics', 'economics:4-1-importance-of-international-trade', '4.1 Importance of International Trade', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Quota”?", "options": ["Goods and services bought from other countries", "Goods and services sold to other countries", "A limit on the quantity of a good that can be imported", "Trade in tangible goods, e.g. cars"]}'::jsonb, '{"answer": 2, "explain": "“Quota” means: A limit on the quantity of a good that can be imported"}'::jsonb),
('economics:4-1-importance-of-international-trade:match:638a8488', 'economics', 'economics:4-1-importance-of-international-trade', '4.1 Importance of International Trade', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Free trade agreement”?", "options": ["Average costs falling as a firm''s output increases", "Members remove tariffs/quotas between themselves but keep their own deals with outsiders", "Trade in tangible goods, e.g. cars", "Selling a surplus of a good abroad at a very low price to undercut local producers"]}'::jsonb, '{"answer": 1, "explain": "“Free trade agreement” means: Members remove tariffs/quotas between themselves but keep their own deals with outsiders"}'::jsonb),
('economics:4-1-importance-of-international-trade:match:16459ad0', 'economics', 'economics:4-1-importance-of-international-trade', '4.1 Importance of International Trade', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Trade bloc”?", "options": ["A limit on the quantity of a good that can be imported", "Trade in tangible goods, e.g. cars", "Selling a surplus of a good abroad at a very low price to undercut local producers", "A group of countries that reduce trade barriers between members"]}'::jsonb, '{"answer": 3, "explain": "“Trade bloc” means: A group of countries that reduce trade barriers between members"}'::jsonb),
('economics:4-1-importance-of-international-trade:match:88e89fe3', 'economics', 'economics:4-1-importance-of-international-trade', '4.1 Importance of International Trade', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Structural unemployment”?", "options": ["Unemployment when workers'' skills no longer match the jobs available, e.g. after an industry declines", "Goods and services sold to other countries", "A limit on the quantity of a good that can be imported", "Trade in tangible goods, e.g. cars"]}'::jsonb, '{"answer": 0, "explain": "“Structural unemployment” means: Unemployment when workers'' skills no longer match the jobs available, e.g. after an industry declines"}'::jsonb),
('economics:4-1-importance-of-international-trade:match:84863a72', 'economics', 'economics:4-1-importance-of-international-trade', '4.1 Importance of International Trade', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Dumping”?", "options": ["A tax charged on an imported good", "Selling a surplus of a good abroad at a very low price to undercut local producers", "A country focusing its resources on producing what it does relatively most efficiently", "Trade in intangible services, e.g. finance or tourism"]}'::jsonb, '{"answer": 1, "explain": "“Dumping” means: Selling a surplus of a good abroad at a very low price to undercut local producers"}'::jsonb),
('economics:4-2-balance-of-payments:exam:20d47add', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'exam', 'mcq', 1, '{"num": "Q2", "question": "Which one of the following is least likely to be an economic policy objective for the government?", "options": ["Boosting economic growth", "Boosting employment", "Encouraging imports", "Stimulating exports"], "hint": "Read ''least likely''. Three of these are things a government actively wants. Which one would make the current account WORSE?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1 1a)</h5>\n<p><strong>Answer: C — Encouraging imports</strong></p>\n<ul>\n<li>Growth, employment and exports are all standard government objectives. Encouraging imports would worsen the current account, so no government would target it.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:4-2-balance-of-payments:exam:b58c2d52', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'exam', 'mcq', 1, '{"num": "Q4", "question": "A current account surplus will most likely lead to", "options": ["a decrease in the country''s debt", "a decrease in the exchange rate", "a decrease in the rate of inflation", "an increase in unemployment"], "hint": "A surplus means export income more than covers import spending. Three of these options are what a DEFICIT does — only one fits a surplus.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: A — a decrease in the country''s debt</strong></p>\n<ul>\n<li>With a surplus, income from exports more than covers the cost of imports, so the country''s overall debt falls. A surplus tends to RAISE the exchange rate (more demand for the currency), RAISE demand-pull inflation (more demand for domestic output) and LOWER unemployment (firms hire to meet export demand) — so B, C and D are all the wrong way round.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>A significant proportion of candidates answered A correctly.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:4-2-balance-of-payments:exam:7971fe85', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'exam', 'mcq', 1, '{"num": "Q5", "question": "A country is experiencing structural problems which means overpriced and poor-quality goods being produced. This will lead to", "options": ["a decision to reduce the amount of regulation in the market", "a deficit of the balance of payments on current account", "an increase in the demand for the country''s exports", "the country''s central bank deciding to increase interest rates"], "hint": "Overpriced and poor quality is the classic ''bad reputation'' cause. Ask what that does to export demand — then which way the current account moves.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: B — a deficit of the balance of payments on current account</strong></p>\n<ul>\n<li>Overpriced, poor-quality goods reduce demand for the country''s exports and push its own consumers towards imports, so the current account moves into deficit. C is the opposite of what happens; A and D are possible policy responses, not the direct result.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>A significant proportion of candidates answered B correctly.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:4-2-balance-of-payments:exam:3ac8db71', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'exam', 'mcq', 1, '{"num": "Q6", "question": "What does this diagram show?", "options": ["Exports decreased by more than imports between 2019 and 2020", "Exports increased by less than imports between 2020 and 2021", "The demand for UK exports was greater in 2021 than in 2018", "The UK''s imports were always greater than its exports"], "caseStudy": "<p>The diagram shows import and export data for the UK from 2017 to 2021.</p>\n<img src=\"/images/economics/4-2-uk-imports-exports-2017-2021-chart-extracted.png\" alt=\"Line chart from the OCR exam paper showing UK imports and exports in £bn from 2017 to 2021, with a vertical axis from 550 to 750. The dashed Imports line runs at about 670 in 2017, 707 in 2018 and peaks at 737 in 2019, then falls sharply to about 611 in 2020 before recovering to about 654 in 2021. The solid Exports line runs at about 641 in 2017, 674 in 2018 and 700 in 2019, then falls to about 618 in 2020 and rises to about 637 in 2021. Imports are above exports every year except 2020, where the two lines cross and exports are slightly higher\" style=\"display:block;width:100%;max-width:540px;margin:14px auto;border:1px solid var(--border);border-radius:8px;background:#fff;padding:6px;\" />", "hint": "The DASHED line is Imports and the SOLID line is Exports — check where each ends against the labels. Watch 2020 closely: the lines cross there, which is what kills option D.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2) · Quantitative skills</h5>\n<p><strong>Answer: B — Exports increased by less than imports between 2020 and 2021</strong></p>\n<ul>\n<li>From 2020 to 2021 exports rose from about 618 to 637 (about +19), while imports rose from about 611 to 654 (about +43) — so exports increased by less. A is wrong: between 2019 and 2020 exports fell about 82 (700→618) but imports fell about 126 (737→611), so exports fell by LESS, not more. C is wrong: exports were about 637 in 2021, below their 2018 level of about 674. D is wrong because the lines cross in 2020, when imports (about 611) dipped just below exports (about 618).</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>A significant proportion of candidates answered B correctly.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:4-2-balance-of-payments:exam:8711aa85', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'exam', 'mcq', 1, '{"num": "Q7", "question": "Which of these is not included in the UK''s balance of payments on current account?", "options": ["A Spanish firm buying land in the UK to build a factory", "A UK consumer spending money while on holiday in Greece", "Foreign aid money sent from the UK to a less developed country", "Interest earned by a UK individual from a bank account in France"], "hint": "Read the ''not''. Sort each option into the four current-account components — goods, services, income flows, transfers. The one that fits NONE of them is investment, which belongs to a different account entirely.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1a)</h5>\n<p><strong>Answer: A — A Spanish firm buying land in the UK to build a factory</strong></p>\n<ul>\n<li>Buying land to build a factory is investment, so it is recorded in the FINANCIAL account, not the current account. The other three all belong to the current account: holiday spending in Greece is an import of services, foreign aid is a transfer, and interest from a French bank account is an income flow.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>This was a question where several candidates selected B or D demonstrating a confusion over the concept of balance of payments on current account.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:4-2-balance-of-payments:exam:2427bc63', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'exam', 'mcq', 1, '{"num": "Q8", "question": "What will help to create a balance of payments deficit on the UK current account?", "options": ["A depreciation of the UK exchange rate", "A fall in GDP per capita in the UK", "A net outflow of investment income", "An increase in the quality of UK output"], "hint": "Three of these would IMPROVE the current account. Look for the one that is money physically leaving the current account.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: C — A net outflow of investment income</strong></p>\n<ul>\n<li>A net outflow of investment income is money leaving the income flows component, which pushes the current account towards deficit. A depreciation makes exports cheaper and imports dearer (improving it); a fall in GDP per capita means lower incomes and so fewer imports (improving it); and better quality output raises export demand (improving it).</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>Although a significant proportion of candidates correctly answered C, there was a wider variety of responses. The answer is based on the fact that a net outflow of investment income is the only factor that would directly help lead to a deficit on the current account.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:4-2-balance-of-payments:exam:8ec0a4ef', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'exam', 'mcq', 1, '{"num": "Q9", "question": "One likely benefit of supply side policy is to improve a country''s balance of payments. This is because supply side policy can", "options": ["improve the productivity of the UK labour force", "lead to a higher rate of inflation in the UK", "lead to higher consumption by UK consumers", "mean free trade agreements are cancelled"], "hint": "Supply side policy works on the economy''s productive capacity. Two of the distractors (higher inflation, higher consumption) would actually make the balance of payments WORSE.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: A — improve the productivity of the UK labour force</strong></p>\n<ul>\n<li>Higher productivity lowers costs per unit, so UK exports become more internationally competitive and the balance of payments improves. Higher inflation would make exports less competitive, and higher consumption would suck in more imports — both would worsen it.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>A significant proportion of candidates correctly answered A.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:4-2-balance-of-payments:exam:9279203b', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'exam', 'mcq', 1, '{"num": "Q10", "question": "Which of these statements is correct?", "options": ["Exports were always greater than imports in the UK", "Germany moved from a trade surplus to a trade deficit in 2020", "Imports were greater than exports in China between 2017 and 2019", "The UK''s trade balance improved the most between 2015 and 2020"], "caseStudy": "<p>The balance of trade is the main component of a country''s balance of payments on current account. The diagram shows the balance of trade for three countries.</p>\n<img src=\"/images/economics/4-2-balance-of-trade-uk-germany-china-chart-extracted.png\" alt=\"Line chart from the OCR exam paper showing the balance of trade in $bn for three countries from 2015 to 2020, with a vertical axis from -100 to 400. China starts highest at about 358 in 2015, falls to about 255 in 2016, 215 in 2017 and a low of about 87 in 2018, recovers to about 133 in 2019 and rises steeply to about 370 in 2020. Germany is roughly flat at about 253 in 2015, 258 in 2016, 260 in 2017, 247 in 2018, 220 in 2019 and 222 in 2020. The UK is the only country below zero, at about -48 in 2015, -47 in 2016, -37 in 2017, -40 in 2018, -30 in 2019, rising to about 0 in 2020. China and Germany are in surplus every year; the UK is in deficit throughout\" style=\"display:block;width:100%;max-width:540px;margin:14px auto;border:1px solid var(--border);border-radius:8px;background:#fff;padding:6px;\" />", "hint": "A line ABOVE zero is a surplus (exports > imports); BELOW zero is a deficit. For D, compare the SIZE of each country''s change, not its level — the UK starts lowest but climbs about 48, more than anyone else gains.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: D — The UK''s trade balance improved the most between 2015 and 2020</strong></p>\n<ul>\n<li>The UK rose from about −48 to about 0, an improvement of roughly 48. China rose from about 358 to about 370 (about +12) and Germany fell from about 253 to about 222. So the UK improved the most, even though it remained the weakest in level terms.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>''A'' is incorrect because the balance of payments on current account was always in deficit. ''B'' is incorrect because the German balance of payments on current account is always in surplus (as is the case in China rendering ''C'' incorrect). D is correct because the trade balance does improve the most for UK between 2015–2019.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:4-2-balance-of-payments:exam:93306e60', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'exam', 'mcq', 1, '{"num": "Q12", "question": "The UK has a current account deficit. Which of the following is most likely to lead to this continuing in the future?", "options": ["Falling domestic demand", "Greater capital imports", "Higher overseas investment", "Lower productivity"], "hint": "You want the option that keeps UK goods UNCOMPETITIVE. Falling domestic demand would actually cut imports and reduce the deficit.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: D — Lower productivity</strong></p>\n<ul>\n<li>Lower productivity raises producers'' costs per unit, making UK goods and services less internationally competitive, so exports fall and the deficit persists. Falling domestic demand would reduce imports and so shrink the deficit.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>The majority of candidates gave Option D as the correct response to this question. Lower productivity is likely to have a negative effect on producers'' costs and would make UK goods and services less internationally competitive.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:4-2-balance-of-payments:exam:161891dc', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'exam', 'mcq', 1, '{"num": "Q13", "question": "What is the deficit as a percentage of national output?", "options": ["5%", "10%", "20%", "50%"], "caseStudy": "<p>An economy has a current account deficit of £10 billion. Its national output is £200 billion.</p>", "hint": "Deficit ÷ national output × 100. Both figures are already in billions, so no unit conversion is needed — just divide 10 by 200.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2) · Quantitative skills</h5>\n<p><strong>Answer: A — 5%</strong></p>\n<ul>\n<li>10 ÷ 200 × 100 = 5%. Expressing a deficit as a share of GDP is how its seriousness is judged — a £10bn deficit is small for an economy producing £200bn.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>A high percentage of candidates gave Option A as the correct response to this question. This was the first question testing quantitative skills, so was more difficult for candidates who had a weakness in this area.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:4-2-balance-of-payments:exam:ec6cb68f', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'exam', 'mcq', 1, '{"num": "Q14", "question": "Which of the following will help to create a balance of payments surplus on the UK current account?", "options": ["A UK government purchase of American aircraft", "A subsidy to UK producers of exported goods", "An increase in UK government tax revenue", "An increase in UK government investment"], "hint": "You need something that raises EXPORTS or cuts IMPORTS. Note that tax revenue is the government''s budget, not the current account — that''s the classic confusion on this topic.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: B — A subsidy to UK producers of exported goods</strong></p>\n<ul>\n<li>A subsidy lowers exporters'' costs, so UK exports become cheaper and more competitive abroad — raising export revenue and moving the current account towards surplus. Buying American aircraft is an import (worsening it), and tax revenue is a government budget matter, not a current account flow.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>A majority of candidates gave Option B as the correct response to this question. This was the answer that should clearly lead to a balance of payments surplus.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:4-2-balance-of-payments:exam:b41c5abd', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'exam', 'mcq', 1, '{"num": "Q15", "question": "Which statement best describes a current account surplus?", "options": ["Revenue from the export of goods and services exceeds the country''s spending on imports", "Revenue from all taxes and other government revenue exceeds government expenditure", "Sum of all incomes in the country exceeds the total value added of all goods and services", "Sum of export revenue and the inflow of income and transfers exceeds the outflow on imports, income and transfers"], "hint": "The word is BEST. Option A is nearly right but covers only goods and services — it leaves out two of the four components. Find the one that includes income and transfers as well.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1a)</h5>\n<p><strong>Answer: D — Sum of export revenue and the inflow of income and transfers exceeds the outflow on imports, income and transfers</strong></p>\n<ul>\n<li>D is the only option covering all four components of the current account. A is incomplete — it mentions only goods and services, omitting income flows and transfers. B describes a government budget surplus, not a current account surplus.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>A majority of candidates gave Option D as the correct response to this question. This required knowledge of the extent of the precise definition for a current account surplus. The question wording highlights this precision, and should have resulted in option A being discarded, by asking for the statement that is ''best''.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:4-2-balance-of-payments:exam:3bcce21f', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'exam', 'mcq', 1, '{"num": "Q18", "question": "Which of the following is an example of a trade in goods in the UK balance of payments on current account?", "options": ["A Japanese car company purchasing a factory in the UK", "A laptop imported into the UK from China", "A UK airline selling transport facilities to a firm in Dubai", "Money earned by a UK firm on investment in Australia"], "hint": "Goods are physical, visible items. Sort the others: buying a factory is investment, transport is a service, and investment earnings are income flows.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: B — A laptop imported into the UK from China</strong></p>\n<ul>\n<li>A laptop is a physical, visible good, so it belongs in trade in goods. Buying a factory is investment (financial account), selling transport is trade in services, and money earned on investment abroad is an income flow.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:4-2-balance-of-payments:exam:b0497f08', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'exam', 'mcq', 1, '{"num": "Q19", "question": "The Balance of Payments on the current account shows the balance of receipts and payments of", "options": ["a country''s international banks", "a typical household", "foreign exchange by a country", "the government"], "hint": "The current account covers the WHOLE country''s dealings with the rest of the world — not one sector of it. Note that ''the government'' is the classic wrong answer here: that would be the budget.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: C — foreign exchange by a country</strong></p>\n<ul>\n<li>The current account records the whole country''s receipts and payments of foreign exchange with the rest of the world. It is not restricted to banks, to households, or to the government — option D is the common confusion with the government''s budget.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:4-2-balance-of-payments:exam:d1d716ea', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'exam', 'mcq', 1, '{"num": "Q22", "question": "Which statement about these countries is correct?", "options": ["The current account deficit as a proportion of GDP is largest for country P", "The current account deficit as a proportion of GDP is largest for country Q", "The current account deficit as a proportion of GDP is largest for country R", "The current account deficit as a proportion of GDP is the same for countries Q and R"], "caseStudy": "<table style=\"width:100%;max-width:440px;margin:12px auto;border-collapse:collapse;text-align:left;font-size:14px;\">\n<tr style=\"border-bottom:1px solid var(--border);\"><th style=\"padding:6px;\">Country</th><th style=\"padding:6px;\">Current account deficit (£ million)</th><th style=\"padding:6px;\">GDP (£ million)</th></tr>\n<tr><td style=\"padding:6px;\">P</td><td style=\"padding:6px;\">2</td><td style=\"padding:6px;\">40</td></tr>\n<tr><td style=\"padding:6px;\">Q</td><td style=\"padding:6px;\">3</td><td style=\"padding:6px;\">80</td></tr>\n<tr><td style=\"padding:6px;\">R</td><td style=\"padding:6px;\">4</td><td style=\"padding:6px;\">100</td></tr>\n</table>\n<p>The table shows the balance of payments deficit on the current account and the size of the Gross Domestic Product (GDP) for three countries.</p>", "hint": "Work out deficit ÷ GDP for all three — don''t just look at the cash deficits. Country P has the SMALLEST deficit in pounds but the largest as a proportion, which is the whole point of the question.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2) · Quantitative skills</h5>\n<p><strong>Answer: A — The current account deficit as a proportion of GDP is largest for country P</strong></p>\n<ul>\n<li>P: 2 ÷ 40 = <strong>5%</strong>. Q: 3 ÷ 80 = 3.75%. R: 4 ÷ 100 = 4%. So P has the largest deficit as a proportion of GDP, even though its cash deficit (£2m) is the smallest of the three — the trap. D is wrong because Q (3.75%) and R (4%) are not the same.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:4-2-balance-of-payments:mcq:73aee209', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'mcq', 'mcq', 1, '{"question": "The balance of payments is best defined as...", "options": ["A record of a country''s total output", "A record of all financial transactions between a country and the rest of the world", "A record of the government''s spending and tax revenue", "A record of a country''s trade in goods only"]}'::jsonb, '{"answer": 1, "explain": "It records ALL international transactions. Confusing it with the government''s budget (tax and spending) is the single most common misconception on this topic."}'::jsonb),
('economics:4-2-balance-of-payments:mcq:5f26f512', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'mcq', 'mcq', 1, '{"question": "Which of these is NOT one of the four components of the current account?", "options": ["Transfers", "Income flows", "Trade in services", "Foreign direct investment in UK factories"]}'::jsonb, '{"answer": 3, "explain": "Investment in factories, land and shares belongs to the FINANCIAL account. The current account''s four parts are trade in goods, trade in services, income flows and transfers."}'::jsonb),
('economics:4-2-balance-of-payments:mcq:62751051', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'mcq', 'mcq', 1, '{"question": "A country''s current account is in surplus when...", "options": ["Export revenue plus inflows of income and transfers exceed the outflows on imports, income and transfers", "Its exports of goods exceed its imports of goods", "Its government revenue exceeds its spending", "Its total output exceeds its total income"]}'::jsonb, '{"answer": 0, "explain": "The ''best'' definition covers all four components, not just goods. A definition mentioning only goods and services is the standard distractor — it''s almost right, which is the trap."}'::jsonb),
('economics:4-2-balance-of-payments:mcq:bbd1f7c1', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'mcq', 'mcq', 1, '{"question": "Goods: exports £200m, imports £350m. Services: exports £400m, imports £100m. Income flows −£20m. Transfers −£20m. The current account balance is...", "options": ["A surplus of £150m", "A surplus of £110m", "A deficit of £70m", "A deficit of £110m"]}'::jsonb, '{"answer": 1, "explain": "Net each component then sum: goods −150, services +300, income −20, transfers −20. −150 + 300 − 20 − 20 = +£110m, a surplus."}'::jsonb),
('economics:4-2-balance-of-payments:mcq:32eeae37', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'mcq', 'mcq', 1, '{"question": "The balance of trade is...", "options": ["The record of a country''s trade in goods and services", "The record of investment flows", "The same as the balance of payments", "The whole of the current account"]}'::jsonb, '{"answer": 0, "explain": "The balance of trade is only the goods and services part. It''s the LARGEST component of the current account, but the current account also includes income flows and transfers."}'::jsonb),
('economics:4-2-balance-of-payments:mcq:72e6cddc', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'mcq', 'mcq', 1, '{"question": "A current account surplus will most likely lead to...", "options": ["A decrease in the country''s debt", "A decrease in the exchange rate", "An increase in unemployment", "A decrease in the rate of inflation"]}'::jsonb, '{"answer": 0, "explain": "Export income more than covers import spending, so the country''s overall debt falls. A surplus tends to RAISE the exchange rate, RAISE inflation pressure and LOWER unemployment — the other three are all backwards."}'::jsonb),
('economics:4-2-balance-of-payments:mcq:a629811c', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'mcq', 'mcq', 1, '{"question": "Which of these is an example of trade in goods in the UK current account?", "options": ["A UK airline selling transport to a firm in Dubai", "Money earned by a UK firm on investment in Australia", "A laptop imported into the UK from China", "A Japanese car company purchasing a factory in the UK"]}'::jsonb, '{"answer": 2, "explain": "A laptop is a physical good. The airline is selling a SERVICE, the investment earnings are INCOME FLOWS, and buying a factory is financial-account investment."}'::jsonb),
('economics:4-2-balance-of-payments:mcq:bb651812', 'economics', 'economics:4-2-balance-of-payments', '4.2 Balance of Payments', 'mcq', 'mcq', 1, '{"question": "A country''s current account deficit is £4 million and its GDP is £100 million. Another country''s deficit is £2 million with GDP of £40 million. Which is true?", "options": ["The second country''s deficit is the larger proportion of GDP", "Both deficits are the same proportion of GDP", "The first country''s deficit is the larger proportion of GDP", "You cannot compare them"]}'::jsonb, '{"answer": 0, "explain": "First: 4/100 = 4%. Second: 2/40 = 5%. The SECOND is larger as a proportion, even though its cash deficit is smaller — which is exactly why deficits are judged relative to GDP."}'::jsonb)
